#include <memory>
#include <string>
#include <vector>

#include "source/extensions/filters/http/custom_header_injection/filter.h"

#include "test/mocks/http/mocks.h"

#include "gmock/gmock.h"
#include "gtest/gtest.h"

using testing::NiceMock;

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {
namespace {

class CustomHeaderInjectionFilterTest : public testing::Test {
public:
  void initializeFilter(std::vector<HeaderEntry> request_headers,
                        std::vector<HeaderEntry> response_headers) {
    auto config = std::make_shared<FilterConfig>();
    config->request_headers_to_add = std::move(request_headers);
    config->response_headers_to_add = std::move(response_headers);
    filter_ = std::make_shared<CustomHeaderInjectionFilter>(config);
    filter_->setDecoderFilterCallbacks(decoder_callbacks_);
    filter_->setEncoderFilterCallbacks(encoder_callbacks_);
  }

  NiceMock<Http::MockStreamDecoderFilterCallbacks> decoder_callbacks_;
  NiceMock<Http::MockStreamEncoderFilterCallbacks> encoder_callbacks_;
  std::shared_ptr<CustomHeaderInjectionFilter> filter_;
};

TEST_F(CustomHeaderInjectionFilterTest, InjectsRequestHeaders) {
  initializeFilter({{"x-custom-request", "req-value"}}, {});

  Http::TestRequestHeaderMapImpl headers{
      {":method", "GET"}, {":path", "/"}, {":authority", "host"}};

  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->decodeHeaders(headers, true));
  EXPECT_EQ("req-value", headers.get(Http::LowerCaseString("x-custom-request"))[0]->value().getStringView());
}

TEST_F(CustomHeaderInjectionFilterTest, InjectsResponseHeaders) {
  initializeFilter({}, {{"x-custom-response", "resp-value"}});

  Http::TestResponseHeaderMapImpl headers{{":status", "200"}};

  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->encodeHeaders(headers, true));
  EXPECT_EQ("resp-value", headers.get(Http::LowerCaseString("x-custom-response"))[0]->value().getStringView());
}

TEST_F(CustomHeaderInjectionFilterTest, InjectsBothRequestAndResponseHeaders) {
  initializeFilter({{"x-req-header", "req-val"}}, {{"x-resp-header", "resp-val"}});

  Http::TestRequestHeaderMapImpl req_headers{
      {":method", "GET"}, {":path", "/"}, {":authority", "host"}};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->decodeHeaders(req_headers, false));
  EXPECT_EQ("req-val", req_headers.get(Http::LowerCaseString("x-req-header"))[0]->value().getStringView());

  Http::TestResponseHeaderMapImpl resp_headers{{":status", "200"}};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->encodeHeaders(resp_headers, false));
  EXPECT_EQ("resp-val", resp_headers.get(Http::LowerCaseString("x-resp-header"))[0]->value().getStringView());
}

TEST_F(CustomHeaderInjectionFilterTest, EmptyConfigNoHeadersInjected) {
  initializeFilter({}, {});

  Http::TestRequestHeaderMapImpl req_headers{
      {":method", "GET"}, {":path", "/"}, {":authority", "host"}};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->decodeHeaders(req_headers, true));
  EXPECT_TRUE(req_headers.get(Http::LowerCaseString("x-custom-request")).empty());

  Http::TestResponseHeaderMapImpl resp_headers{{":status", "200"}};
  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->encodeHeaders(resp_headers, true));
  EXPECT_TRUE(resp_headers.get(Http::LowerCaseString("x-custom-response")).empty());
}

TEST_F(CustomHeaderInjectionFilterTest, PassThroughDataAndTrailers) {
  initializeFilter({}, {});

  Buffer::OwnedImpl data("test data");
  EXPECT_EQ(Http::FilterDataStatus::Continue, filter_->decodeData(data, true));
  EXPECT_EQ(Http::FilterDataStatus::Continue, filter_->encodeData(data, true));

  Http::TestRequestTrailerMapImpl req_trailers;
  EXPECT_EQ(Http::FilterTrailersStatus::Continue, filter_->decodeTrailers(req_trailers));

  Http::TestResponseTrailerMapImpl resp_trailers;
  EXPECT_EQ(Http::FilterTrailersStatus::Continue, filter_->encodeTrailers(resp_trailers));
}

} // namespace
} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

