#include "source/extensions/filters/http/custom_header_injection/config.h"

#include "envoy/registry/registry.h"

#include "source/common/protobuf/protobuf.h"
#include "source/extensions/filters/http/custom_header_injection/filter.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

absl::StatusOr<Http::FilterFactoryCb>
CustomHeaderInjectionFilterFactory::createFilterFactoryFromProto(
    const Protobuf::Message& proto_config, const std::string&,
    Server::Configuration::FactoryContext&) {
  const auto& struct_config =
      dynamic_cast<const ProtobufWkt::Struct&>(proto_config);

  auto filter_config = std::make_shared<FilterConfig>();

  // Parse request_headers field: a Struct of header-name -> header-value
  auto req_it = struct_config.fields().find("request_headers");
  if (req_it != struct_config.fields().end() &&
      req_it->second.has_struct_value()) {
    for (const auto& field : req_it->second.struct_value().fields()) {
      if (field.second.has_string_value()) {
        filter_config->request_headers_to_add.push_back(
            {field.first, field.second.string_value()});
      }
    }
  }

  // Parse response_headers field: a Struct of header-name -> header-value
  auto resp_it = struct_config.fields().find("response_headers");
  if (resp_it != struct_config.fields().end() &&
      resp_it->second.has_struct_value()) {
    for (const auto& field : resp_it->second.struct_value().fields()) {
      if (field.second.has_string_value()) {
        filter_config->response_headers_to_add.push_back(
            {field.first, field.second.string_value()});
      }
    }
  }

  return [filter_config](Http::FilterChainFactoryCallbacks& callbacks) -> void {
    callbacks.addStreamFilter(
        Http::StreamFilterSharedPtr{new CustomHeaderInjectionFilter(filter_config)});
  };
}

ProtobufTypes::MessagePtr CustomHeaderInjectionFilterFactory::createEmptyConfigProto() {
  return std::make_unique<ProtobufWkt::Struct>();
}

/**
 * Static registration for the custom header injection filter. @see RegisterFactory.
 */
REGISTER_FACTORY(CustomHeaderInjectionFilterFactory,
                 Server::Configuration::NamedHttpFilterConfigFactory);

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy
